from typing import Any, Dict, List


class Filter:
    pass


def apply_filters(value: Any) -> Any:
    """Recursively filter out any values that are instances of Filter."""
    if isinstance(value, Filter):
        pass
    elif isinstance(value, List):
        # Cleaner syntax but requires two iterations
        # filtered_list = list(filter(None, map(apply_filters, value)))
        filtered_list = []
        for item in value:
            filtered_item = apply_filters(item)
            if filtered_item is not None:
                filtered_list.append(filtered_item)

        return filtered_list
    elif isinstance(value, Dict):
        # Cleaner syntax but requires two iterations
        # filtered_dict = {
        #     k: apply_filters(v)
        #     for k, v in value.items()
        #     if apply_filters(v)
        # }
        filtered_dict = {}
        for k, v in value.items():
            # Should we omit the key or just the value?
            filtered_value = apply_filters(v)
            if filtered_value is not None:
                filtered_dict[k] = filtered_value

        return filtered_dict
    else:
        return value

from typing import Any, Dict, List, Union
from guardrails.classes.output_type import OutputTypes
from guardrails.logger import logger


class Refrain:
    pass


def check_for_refrain(value: Union[List, Dict]) -> bool:
    if isinstance(value, Refrain):
        return True
    elif isinstance(value, list):
        for item in value:
            if check_for_refrain(item):
                return True
    elif isinstance(value, dict):
        for key, child in value.items():
            if check_for_refrain(child):
                return True

    return False


# Could be a generic instead of Any
def apply_refrain(value: Any, output_type: OutputTypes) -> Any:
    """Recursively check for any values that are instances of Refrain.

    If found, return an empty value of the appropriate type.
    """
    refrain_value = {}
    if output_type == OutputTypes.STRING:
        refrain_value = ""
    elif output_type == OutputTypes.LIST:
        refrain_value = []

    if check_for_refrain(value):
        # If the data contains a `Refain` value, we return an empty
        # value.
        logger.debug("Refrain detected.")
        value = refrain_value

    return value

from copy import deepcopy
from typing import Any, Dict, Optional, Union, cast
import json
from langchain_core.messages import BaseMessage
from langchain_core.runnables import Runnable, RunnableConfig
from guardrails.classes.input_type import InputType
from guardrails.classes.output_type import OT


class BaseRunnable(Runnable):
    name: Union[str, None]

    def invoke(
        self,
        input: InputType,
        config: Optional[RunnableConfig] = None,
        **kwargs: Any,
    ) -> InputType:
        return self._call_with_config(
            self._process_input, input, config, run_type="parser", **kwargs
        )

    def _process_input(self, input: InputType) -> InputType:
        str_input = str(input.content) if isinstance(input, BaseMessage) else str(input)

        validated_output = self._validate(str_input)

        if isinstance(validated_output, Dict):
            validated_output = json.dumps(validated_output)

        if isinstance(input, BaseMessage):
            output = deepcopy(input)
            output.content = validated_output
            return cast(InputType, output)

        return cast(InputType, validated_output)

    def _validate(self, input: str) -> OT:
        raise NotImplementedError

import threading
from typing import Optional

from guardrails.classes.rc import RC


class Settings:
    _instance = None
    _lock = threading.Lock()
    _rc: RC
    _watch_mode_enabled: bool
    """Whether to use a local server for running Guardrails."""
    use_server: Optional[bool]
    """Whether to disable tracing.

    Traces are only ever sent to a telemetry sink you specify via
    environment variables or by instantiating a TracerProvider.
    """
    disable_tracing: Optional[bool]

    def __new__(cls) -> "Settings":
        if cls._instance is None:
            with cls._lock:
                if cls._instance is None:
                    cls._instance = super(Settings, cls).__new__(cls)
                    cls._instance._initialize()
        return cls._instance

    def _initialize(self):
        self.use_server = None
        self.disable_tracing = None
        self._rc = RC.load()
        self._watch_mode_enabled = False

    @property
    def rc(self) -> RC:
        if self._rc is None:
            self._rc = RC.load()
        return self._rc

    @rc.setter
    def rc(self, value: RC):
        self._rc = value

    @property
    def watch_mode_enabled(self) -> bool:
        return self._watch_mode_enabled


